#[napi(object)]
pub struct NativeBuildInfo {
    pub artifact_version: String,
    pub engine_version: String,
    pub query_version: String,
    pub mongreldb_git_sha: String,
}

#[napi(js_name = "buildInfo")]
pub fn build_info() -> NativeBuildInfo {
    let info = mongreldb_query::build_info();
    NativeBuildInfo {
        artifact_version: env!("CARGO_PKG_VERSION").into(),
        engine_version: info.engine_version.into(),
        query_version: info.query_version.into(),
        mongreldb_git_sha: info.mongreldb_git_sha.into(),
    }
}

#[napi(js_name = "minhashMemberHashV1")]
pub fn minhash_member_hash_v1_json(member_json: String) -> napi::Result<String> {
    let member: serde_json::Value = serde_json::from_str(&member_json)
        .map_err(|error| napi::Error::new(napi::Status::InvalidArg, error.to_string()))?;
    mongreldb_core::index::minhash_member_hash_v1(&member)
        .map(|hash| hash.to_string())
        .map_err(|error| napi::Error::new(napi::Status::InvalidArg, error))
}

#[napi]
pub enum ColumnType {
    Bool,
    Int64,
    Float64,
    TimestampNanos,
    Date32,
    Date64,
    Time64,
    Interval,
    Bytes,
    Embedding,
    Decimal128,
    Uuid,
    Json,
    Array,
    Enum,
}

#[napi]
pub enum IndexKindSpec {
    Bitmap,
    FmIndex,
    Ann,
    Sparse,
    MinHash,
    /// Learned zonemap (PGM) for ordered range predicates. Engine SQL aliases:
    /// `brin`, `learned_range`, `range`.
    LearnedRange,
}

#[napi]
pub enum AnnQuantizationSpec {
    BinarySign,
    Dense,
    /// Product quantization (Phase 2 surface; the PQ backend is gated until
    /// implemented). When selected, `product_num_subvectors` is required.
    Product,
}

/// ANN graph/structure algorithm. Orthogonal to [`AnnQuantizationSpec`].
#[napi]
pub enum AnnAlgorithmSpec {
    /// Hierarchical Navigable Small World (default).
    Hnsw,
    /// DiskANN / Vamana single-layer robust-pruned graph.
    DiskAnn,
    /// Inverted file index (k-means centroids + inverted lists).
    Ivf,
}

/// DiskANN (Vamana) build parameters. Used when `ann_algorithm == DiskAnn`.
#[napi(object)]
pub struct DiskAnnOptionsSpec {
    /// Maximum graph degree R. Zero selects the default (64).
    pub r: Option<u32>,
    /// Search-list size L during build. Zero selects the default (128).
    pub l: Option<u32>,
    /// Query-time beam width. Zero selects the default (8).
    pub beam_width: Option<u32>,
    /// alpha × 100 (120 = 1.2). Zero selects the default.
    pub alpha: Option<u32>,
}

/// IVF build and query parameters. Used when `ann_algorithm == Ivf`.
#[napi(object)]
pub struct IvfOptionsSpec {
    /// Number of inverted lists (k-means centroids). Zero selects the default (256).
    pub nlist: Option<u32>,
    /// Number of lists to probe at query time. Zero selects the default (8).
    pub nprobe: Option<u32>,
}

/// Product-quantizer training parameters. Used when
/// `ann_quantization == Product`.
#[napi(object)]
pub struct ProductQuantizerOptionsSpec {
    /// Number of subvectors. Required; must evenly divide the column dimension.
    pub num_subvectors: u16,
    /// Bits per subvector code. Defaults to 8 (the only supported value).
    pub bits: Option<u8>,
    /// Cap on training samples. Zero selects the default.
    pub training_samples: Option<u32>,
    /// Deterministic training seed. Zero selects the default.
    pub seed: Option<BigInt>,
    /// Exact-rerank factor (top k × factor candidates reranked against Dense).
    /// Zero selects the default (5).
    pub rerank_factor: Option<u32>,
}

#[napi(object)]
pub struct ColumnSpec {
    pub id: u16,
    pub name: String,
    pub ty: ColumnType,
    pub primary_key: bool,
    pub nullable: bool,
    /// Required when `ty == Embedding`.
    pub embedding_dim: Option<u32>,
    /// Optional default value for schema-evolution back-fill. Currently only
    /// validated; applying defaults to existing rows is not yet implemented.
    pub default_value: Option<Cell>,
    /// Optional dynamic default expression: `"now"` or `"uuid"`. Takes
    /// precedence over `default_value` when set.
    pub default_expr: Option<String>,
    /// Required when `ty == Enum`: the list of allowed variant strings.
    pub enum_variants: Option<Vec<String>>,
    /// Engine-managed monotonic identity allocator for an `Int64` primary key.
    /// When `true`, the engine assigns the next counter value on insert if the
    /// column is omitted/null, and explicit ids advance the counter past them.
    /// Mutually exclusive with `nullable`; requires `primary_key` and `Int64`.
    /// Defaults to `false` (omitted/null).
    pub auto_increment: Option<bool>,
    /// Encrypt this column's page payload at rest (requires an encrypted db).
    pub encrypted: Option<bool>,
    /// Encrypt the column but keep it queryable via deterministic equality
    /// tokens / order-preserving encoding (requires an encrypted db).
    pub encrypted_indexable: Option<bool>,
    /// Portable `EmbeddingSource` JSON for embedding columns.
    pub embedding_source_json: Option<String>,
}

#[napi(object)]
pub struct IndexSpec {
    pub name: String,
    pub column_id: u16,
    pub kind: IndexKindSpec,
    /// ANN representation. Defaults to BinarySign; ignored for other kinds.
    pub ann_quantization: Option<AnnQuantizationSpec>,
    /// ANN graph/structure algorithm (Phase 2). Defaults to HNSW; ignored for
    /// other kinds. Orthogonal to `ann_quantization`.
    pub ann_algorithm: Option<AnnAlgorithmSpec>,
    /// DiskANN tuning; read when `ann_algorithm == DiskAnn`.
    pub diskann: Option<DiskAnnOptionsSpec>,
    /// IVF tuning; read when `ann_algorithm == Ivf`.
    pub ivf: Option<IvfOptionsSpec>,
    /// Product-quantizer training; read when `ann_quantization == Product`.
    pub product: Option<ProductQuantizerOptionsSpec>,
    pub predicate: Option<String>,
    pub ann_m: Option<u32>,
    pub ann_ef_construction: Option<u32>,
    pub ann_ef_search: Option<u32>,
    pub minhash_permutations: Option<u32>,
    pub minhash_bands: Option<u32>,
    pub learned_range_epsilon: Option<u32>,
}

#[napi(object)]
pub struct IndexJobInfo {
    pub job_id: BigInt,
    pub state: String,
    pub progress: f64,
    pub done: BigInt,
    pub total: BigInt,
    pub error: Option<String>,
}

fn index_job_info(record: mongreldb_core::JobRecord) -> IndexJobInfo {
    IndexJobInfo {
        job_id: BigInt::from(record.job_id),
        state: format!("{:?}", record.state).to_ascii_lowercase(),
        progress: record.progress.fraction,
        done: BigInt::from(record.progress.done),
        total: BigInt::from(record.progress.total),
        error: record.error,
    }
}

pub struct IndexJobWaitTask {
    db: Arc<CoreDatabase>,
    job_id: u64,
    timeout: std::time::Duration,
}

impl napi::Task for IndexJobWaitTask {
    type Output = Result<mongreldb_core::JobRecord, mongreldb_core::MongrelError>;
    type JsValue = IndexJobInfo;

    fn compute(&mut self) -> napi::Result<Self::Output> {
        Ok(self
            .db
            .job_registry()
            .wait_terminal(self.job_id, self.timeout)
            .map_err(mongreldb_core::MongrelError::from))
    }

    fn resolve(&mut self, _env: Env, output: Self::Output) -> napi::Result<Self::JsValue> {
        output.map(index_job_info).map_err(to_napi)
    }
}

/// Result of a `compactAll` operation.
#[napi(object)]
pub struct CompactStats {
    /// Number of tables that were merged into a single run.
    pub compacted: u32,
    /// Number of tables skipped (fewer than 2 runs, or compaction failed).
    pub skipped: u32,
}

/// Page-cache statistics for one table (hits / misses / lock contention).
#[napi(object)]
pub struct CacheStatsJs {
    pub hits: i64,
    pub misses: i64,
    /// Lookups skipped because the cache shard's lock was contended.
    pub try_lock_misses: i64,
    /// Fraction of lookups served from cache in `[0, 1]`.
    pub hit_rate: f64,
}

/// Trigger execution policy — recursion, depth caps, loop limits.
#[napi(object)]
pub struct TriggerConfigJs {
    pub recursive_triggers: bool,
    pub max_depth: u32,
    pub max_loop_iterations: u32,
}

/// Index build policy: defer to first query (fastest ingest) or build eagerly.
#[napi]
pub enum IndexBuildPolicyJs {
    /// Defer index building to the first query/flush — fastest ingest (default).
    Deferred,
    /// Build and checkpoint indexes inside the bulk load — fastest first query.
    Eager,
}

