fn to_type_id(
    ty: &ColumnType,
    embedding_dim: Option<u32>,
    enum_variants: Option<&[String]>,
) -> napi::Result<TypeId> {
    Ok(match ty {
        ColumnType::Bool => TypeId::Bool,
        ColumnType::Int64 => TypeId::Int64,
        ColumnType::Float64 => TypeId::Float64,
        ColumnType::TimestampNanos => TypeId::TimestampNanos,
        ColumnType::Date32 => TypeId::Date32,
        ColumnType::Date64 => TypeId::Date64,
        ColumnType::Time64 => TypeId::Time64,
        ColumnType::Interval => TypeId::Interval,
        ColumnType::Bytes => TypeId::Bytes,
        ColumnType::Decimal128 => TypeId::Decimal128 {
            precision: 38,
            scale: 2,
        },
        ColumnType::Uuid => TypeId::Uuid,
        ColumnType::Json => TypeId::Json,
        ColumnType::Array => TypeId::Array { element_type: 0 },
        ColumnType::Enum => TypeId::Enum {
            variants: enum_variants
                .ok_or_else(|| {
                    napi::Error::new(
                        napi::Status::InvalidArg,
                        "enum_variants is required for Enum columns",
                    )
                })?
                .into(),
        },
        ColumnType::Embedding => TypeId::Embedding {
            dim: embedding_dim.ok_or_else(|| {
                napi::Error::new(
                    napi::Status::InvalidArg,
                    "embedding_dim is required for Embedding columns",
                )
            })?,
        },
    })
}

fn from_column_def(column: &ColumnDef) -> ColumnSpec {
    let (ty, embedding_dim, enum_variants) = match &column.ty {
        TypeId::Bool => (ColumnType::Bool, None, None),
        TypeId::Int8
        | TypeId::Int16
        | TypeId::Int32
        | TypeId::Int64
        | TypeId::UInt8
        | TypeId::UInt16
        | TypeId::UInt32
        | TypeId::UInt64 => (ColumnType::Int64, None, None),
        TypeId::Float32 | TypeId::Float64 => (ColumnType::Float64, None, None),
        TypeId::TimestampNanos => (ColumnType::TimestampNanos, None, None),
        TypeId::Date32 => (ColumnType::Date32, None, None),
        TypeId::Date64 => (ColumnType::Date64, None, None),
        TypeId::Time64 => (ColumnType::Time64, None, None),
        TypeId::Interval => (ColumnType::Interval, None, None),
        TypeId::Bytes => (ColumnType::Bytes, None, None),
        TypeId::Embedding { dim } => (ColumnType::Embedding, Some(*dim), None),
        TypeId::Decimal128 { .. } => (ColumnType::Decimal128, None, None),
        TypeId::Uuid => (ColumnType::Uuid, None, None),
        TypeId::Json => (ColumnType::Json, None, None),
        TypeId::Array { .. } => (ColumnType::Array, None, None),
        TypeId::Enum { variants } => (ColumnType::Enum, None, Some(variants.to_vec())),
    };
    ColumnSpec {
        id: column.id,
        name: column.name.clone(),
        ty,
        primary_key: column.flags.contains(ColumnFlags::PRIMARY_KEY),
        nullable: column.flags.contains(ColumnFlags::NULLABLE),
        embedding_dim,
        default_value: match &column.default_value {
            Some(DefaultExpr::Static(v)) => Some(from_value(v, column.id)),
            _ => None,
        },
        default_expr: match column.default_value {
            Some(DefaultExpr::Now) => Some("now".into()),
            Some(DefaultExpr::Uuid) => Some("uuid".into()),
            _ => None,
        },
        enum_variants,
        auto_increment: Some(column.flags.contains(ColumnFlags::AUTO_INCREMENT)),
        encrypted: Some(column.flags.contains(ColumnFlags::ENCRYPTED)),
        encrypted_indexable: Some(column.flags.contains(ColumnFlags::ENCRYPTED_INDEXABLE)),
        embedding_source_json: column
            .embedding_source
            .as_ref()
            .and_then(|source| serde_json::to_string(source).ok()),
    }
}

fn to_column_flags(column: &ColumnSpec) -> ColumnFlags {
    let mut flags = ColumnFlags::empty();
    if column.primary_key {
        flags = flags.with(ColumnFlags::PRIMARY_KEY);
    }
    if column.nullable {
        flags = flags.with(ColumnFlags::NULLABLE);
    }
    if column.encrypted.unwrap_or(false) {
        flags = flags.with(ColumnFlags::ENCRYPTED);
    }
    if column.encrypted_indexable.unwrap_or(false) {
        flags = flags.with(ColumnFlags::ENCRYPTED_INDEXABLE);
    }
    if column.auto_increment.unwrap_or(false) {
        flags = flags.with(ColumnFlags::AUTO_INCREMENT);
    }
    flags
}

/// Convert a JS `ColumnSpec`'s default fields into an engine `DefaultExpr`.
fn build_default_expr(c: &ColumnSpec, ty: &TypeId) -> napi::Result<Option<DefaultExpr>> {
    match c.default_expr.as_deref() {
        Some("now") => Ok(Some(DefaultExpr::Now)),
        Some("uuid") => Ok(Some(DefaultExpr::Uuid)),
        Some(other) => Err(napi::Error::new(
            napi::Status::InvalidArg,
            format!("unknown default_expr \"{other}\""),
        )),
        None => match &c.default_value {
            Some(cell) => Ok(Some(DefaultExpr::Static(cell.to_value(ty)?))),
            None => Ok(None),
        },
    }
}

fn build_schema(spec: SchemaSpec) -> napi::Result<Schema> {
    let columns = spec
        .columns
        .into_iter()
        .map(|c| {
            let flags = to_column_flags(&c);
            let ty = to_type_id(&c.ty, c.embedding_dim, c.enum_variants.as_deref())?;
            let default_value = build_default_expr(&c, &ty)?;
            let embedding_source = c
                .embedding_source_json
                .as_deref()
                .map(serde_json::from_str)
                .transpose()
                .map_err(|error| {
                    napi::Error::new(
                        napi::Status::InvalidArg,
                        format!("invalid embedding_source_json: {error}"),
                    )
                })?;
            Ok::<ColumnDef, napi::Error>(ColumnDef {
                id: c.id,
                name: c.name,
                ty,
                flags,
                default_value,
                embedding_source,
            })
        })
        .collect::<napi::Result<Vec<_>>>()?;
    let indexes = spec.indexes.into_iter().map(index_definition).collect();
    Ok(Schema {
        schema_id: 1,
        columns,
        indexes,
        colocation: Vec::new(),
        constraints: Default::default(),
        clustered: false,
    })
}

fn index_definition(spec: IndexSpec) -> IndexDef {
    let kind = match spec.kind {
        IndexKindSpec::Bitmap => IndexKind::Bitmap,
        IndexKindSpec::FmIndex => IndexKind::FmIndex,
        IndexKindSpec::Ann => IndexKind::Ann,
        IndexKindSpec::Sparse => IndexKind::Sparse,
        IndexKindSpec::MinHash => IndexKind::MinHash,
        IndexKindSpec::LearnedRange => IndexKind::LearnedRange,
    };
    IndexDef {
        name: spec.name,
        column_id: spec.column_id,
        kind,
        predicate: spec.predicate,
        options: mongreldb_core::schema::IndexOptions {
            ann: (kind == IndexKind::Ann).then_some(mongreldb_core::schema::AnnOptions {
                quantization: match spec
                    .ann_quantization
                    .unwrap_or(AnnQuantizationSpec::BinarySign)
                {
                    AnnQuantizationSpec::BinarySign => {
                        mongreldb_core::schema::AnnQuantization::BinarySign
                    }
                    AnnQuantizationSpec::Dense => mongreldb_core::schema::AnnQuantization::Dense,
                    AnnQuantizationSpec::Product => {
                        // num_subvectors is required for Product; the PQ
                        // backend itself is gated behind validate_options
                        // until Phase 3, but the option shape is wired. A
                        // missing `product` spec leaves num_subvectors = 0,
                        // which validate_options rejects with a clear message.
                        let num_subvectors =
                            spec.product.as_ref().map(|p| p.num_subvectors).unwrap_or(0);
                        let bits = spec.product.as_ref().and_then(|p| p.bits).unwrap_or(8);
                        mongreldb_core::schema::AnnQuantization::Product {
                            num_subvectors,
                            bits,
                        }
                    }
                },
                algorithm: match spec.ann_algorithm.unwrap_or(AnnAlgorithmSpec::Hnsw) {
                    AnnAlgorithmSpec::Hnsw => mongreldb_core::schema::AnnAlgorithm::Hnsw,
                    AnnAlgorithmSpec::DiskAnn => mongreldb_core::schema::AnnAlgorithm::DiskAnn,
                    AnnAlgorithmSpec::Ivf => mongreldb_core::schema::AnnAlgorithm::Ivf,
                },
                diskann: spec.diskann.as_ref().map(|options| {
                    let defaults = mongreldb_core::schema::DiskAnnOptions::default();
                    mongreldb_core::schema::DiskAnnOptions {
                        r: options.r.map(|v| v as usize).unwrap_or(defaults.r),
                        l: options.l.map(|v| v as usize).unwrap_or(defaults.l),
                        beam_width: options
                            .beam_width
                            .map(|v| v as usize)
                            .unwrap_or(defaults.beam_width),
                        alpha: options.alpha.unwrap_or(defaults.alpha),
                    }
                }),
                ivf: spec.ivf.as_ref().map(|options| {
                    let defaults = mongreldb_core::schema::IvfOptions::default();
                    mongreldb_core::schema::IvfOptions {
                        nlist: options.nlist.map(|v| v as usize).unwrap_or(defaults.nlist),
                        nprobe: options
                            .nprobe
                            .map(|v| v as usize)
                            .unwrap_or(defaults.nprobe),
                        training_samples: defaults.training_samples,
                    }
                }),
                product: spec.product.as_ref().map(|options| {
                    let defaults = mongreldb_core::schema::ProductQuantizerOptions::default();
                    mongreldb_core::schema::ProductQuantizerOptions {
                        training_samples: options
                            .training_samples
                            .map(|v| v as usize)
                            .unwrap_or(defaults.training_samples),
                        seed: options
                            .seed
                            .as_ref()
                            .map(|v| v.get_u64().1)
                            .unwrap_or(defaults.seed),
                        rerank_factor: options
                            .rerank_factor
                            .map(|v| v as usize)
                            .unwrap_or(defaults.rerank_factor),
                    }
                }),
                m: spec
                    .ann_m
                    .map(|value| value as usize)
                    .unwrap_or_else(|| mongreldb_core::schema::AnnOptions::default().m),
                ef_construction: spec
                    .ann_ef_construction
                    .map(|value| value as usize)
                    .unwrap_or_else(|| {
                        mongreldb_core::schema::AnnOptions::default().ef_construction
                    }),
                ef_search: spec
                    .ann_ef_search
                    .map(|value| value as usize)
                    .unwrap_or_else(|| mongreldb_core::schema::AnnOptions::default().ef_search),
            }),
            minhash: (kind == IndexKind::MinHash).then_some(
                mongreldb_core::schema::MinHashOptions {
                    permutations: spec
                        .minhash_permutations
                        .map(|value| value as usize)
                        .unwrap_or_else(|| {
                            mongreldb_core::schema::MinHashOptions::default().permutations
                        }),
                    bands: spec
                        .minhash_bands
                        .map(|value| value as usize)
                        .unwrap_or_else(|| mongreldb_core::schema::MinHashOptions::default().bands),
                },
            ),
            learned_range: (kind == IndexKind::LearnedRange).then_some(
                mongreldb_core::schema::LearnedRangeOptions {
                    epsilon: spec
                        .learned_range_epsilon
                        .map(|value| value as usize)
                        .unwrap_or_else(|| {
                            mongreldb_core::schema::LearnedRangeOptions::default().epsilon
                        }),
                },
            ),
        },
    }
}

fn procedure_from_spec(spec: ProcedureSpec) -> napi::Result<mongreldb_core::StoredProcedure> {
    let parsed: mongreldb_core::StoredProcedure =
        serde_json::from_str(&spec.json).map_err(|e| {
            napi::Error::new(
                napi::Status::InvalidArg,
                format!("invalid procedure JSON: {e}"),
            )
        })?;
    mongreldb_core::StoredProcedure::new(parsed.name, parsed.mode, parsed.params, parsed.body, 0)
        .map_err(to_napi)
}

fn procedure_info(procedure: &mongreldb_core::StoredProcedure) -> napi::Result<ProcedureInfo> {
    Ok(ProcedureInfo {
        json: serde_json::to_string(procedure).map_err(|e| {
            napi::Error::new(
                napi::Status::GenericFailure,
                format!("procedure encode: {e}"),
            )
        })?,
    })
}

fn trigger_from_spec(spec: TriggerSpec) -> napi::Result<mongreldb_core::StoredTrigger> {
    let parsed: mongreldb_core::StoredTrigger = serde_json::from_str(&spec.json).map_err(|e| {
        napi::Error::new(
            napi::Status::InvalidArg,
            format!("invalid trigger JSON: {e}"),
        )
    })?;
    mongreldb_core::StoredTrigger::new(
        parsed.name,
        mongreldb_core::TriggerDefinition {
            target: parsed.target,
            timing: parsed.timing,
            event: parsed.event,
            update_of: parsed.update_of,
            target_columns: parsed.target_columns,
            when: parsed.when,
            program: parsed.program,
        },
        0,
    )
    .map_err(to_napi)
}

fn trigger_info(trigger: &mongreldb_core::StoredTrigger) -> napi::Result<TriggerInfo> {
    Ok(TriggerInfo {
        json: serde_json::to_string(trigger).map_err(|e| {
            napi::Error::new(napi::Status::GenericFailure, format!("trigger encode: {e}"))
        })?,
    })
}

fn procedure_args(
    opts: Option<ProcedureCallOptions>,
) -> napi::Result<std::collections::HashMap<String, Value>> {
    let Some(opts) = opts else {
        return Ok(std::collections::HashMap::new());
    };
    let Some(args_json) = opts.args_json else {
        return Ok(std::collections::HashMap::new());
    };
    let raw: serde_json::Value = serde_json::from_str(&args_json).map_err(|e| {
        napi::Error::new(
            napi::Status::InvalidArg,
            format!("invalid procedure args JSON: {e}"),
        )
    })?;
    let obj = raw.as_object().ok_or_else(|| {
        napi::Error::new(
            napi::Status::InvalidArg,
            "procedure args JSON must be an object",
        )
    })?;
    obj.iter()
        .map(|(key, value)| Ok((key.clone(), json_to_core_value(value)?)))
        .collect()
}

fn json_to_core_value(value: &serde_json::Value) -> napi::Result<Value> {
    Ok(match value {
        serde_json::Value::Null => Value::Null,
        serde_json::Value::Bool(value) => Value::Bool(*value),
        serde_json::Value::Number(value) => {
            if let Some(value) = value.as_i64() {
                Value::Int64(value)
            } else if let Some(value) = value.as_f64() {
                Value::Float64(value)
            } else {
                return Err(napi::Error::new(
                    napi::Status::InvalidArg,
                    "unsupported JSON number",
                ));
            }
        }
        serde_json::Value::String(value) => Value::Bytes(value.as_bytes().to_vec()),
        serde_json::Value::Array(_) | serde_json::Value::Object(_) => {
            return Err(napi::Error::new(
                napi::Status::InvalidArg,
                "procedure args only support scalar JSON values",
            ));
        }
    })
}

// ── values ────────────────────────────────────────────────────────────────

/// A single cell value. Only the field matching the column type is read; the
/// rest are ignored. `bytes` is raw; `text` is UTF-8 (use for `Bytes` columns
/// when the value is a string).
#[napi(object)]
pub struct Cell {
    pub column_id: u16,
    pub int64: Option<BigInt>,
    pub float64: Option<f64>,
    pub boolean: Option<bool>,
    pub text: Option<String>,
    pub bytes: Option<Buffer>,
    pub embedding: Option<Vec<f64>>,
    /// Sparse (SPLADE) token ids, paired with `sparse_weights`; bincoded into a
    /// Bytes value for a `Sparse` column on insert.
    pub sparse_tokens: Option<Vec<u32>>,
    pub sparse_weights: Option<Vec<f64>>,
}

impl Cell {
    fn empty(column_id: u16) -> Self {
        Self {
            column_id,
            int64: None,
            float64: None,
            boolean: None,
            text: None,
            bytes: None,
            embedding: None,
            sparse_tokens: None,
            sparse_weights: None,
        }
    }

    fn to_value(&self, ty: &TypeId) -> napi::Result<Value> {
        // A cell whose value field for its column type is absent represents SQL
        // NULL. Callers that mean zero/empty must set the field explicitly.
        Ok(match ty {
            TypeId::Bool => match self.boolean {
                Some(b) => Value::Bool(b),
                None => Value::Null,
            },
            TypeId::Int64 | TypeId::TimestampNanos | TypeId::Date32 => match self.int64.as_ref() {
                Some(n) => Value::Int64(bigint_to_i64(n)?),
                None => Value::Null,
            },
            TypeId::Float64 => match self.float64 {
                Some(f) => Value::Float64(f),
                None => Value::Null,
            },
            TypeId::Enum { .. } => match &self.text {
                Some(s) => Value::Bytes(s.as_bytes().to_vec()),
                None => Value::Null,
            },
            TypeId::Bytes => {
                if let Some(tokens) = &self.sparse_tokens {
                    // A `Sparse` column maps to Bytes; bincode `Vec<(u32, f32)>`
                    // so the engine's sparse index reads the tokens.
                    let weights = self.sparse_weights.clone().unwrap_or_default();
                    let terms: Vec<(u32, f32)> = tokens
                        .iter()
                        .zip(weights.into_iter().chain(std::iter::repeat(1.0)))
                        .map(|(t, w)| (*t, w as f32))
                        .collect();
                    Value::Bytes(
                        bincode::serialize(&terms)
                            .map_err(|e| napi::Error::from_reason(e.to_string()))?,
                    )
                } else {
                    match (&self.text, &self.bytes) {
                        (Some(s), _) => Value::Bytes(s.as_bytes().to_vec()),
                        (None, Some(b)) => Value::Bytes(b.to_vec()),
                        (None, None) => Value::Null,
                    }
                }
            }
            TypeId::Embedding { .. } => {
                Value::Embedding(self.embedding.iter().flatten().map(|x| *x as f32).collect())
            }
            _ => Value::Null,
        })
    }
}

fn from_value(v: &Value, column_id: u16) -> Cell {
    let mut cell = Cell::empty(column_id);
    match v {
        Value::Null => {}
        Value::Bool(b) => cell.boolean = Some(*b),
        Value::Int64(n) => cell.int64 = Some(BigInt::from(*n)),
        Value::Float64(f) => cell.float64 = Some(*f),
        Value::Bytes(b) => match std::str::from_utf8(b) {
            Ok(s) => cell.text = Some(s.to_string()),
            Err(_) => cell.bytes = Some(Buffer::from(b.clone())),
        },
        Value::Embedding(e) => cell.embedding = Some(e.iter().map(|x| *x as f64).collect()),
        Value::GeneratedEmbedding(value) => {
            cell.embedding = Some(value.vector.iter().map(|x| *x as f64).collect());
        }
        Value::Decimal(_) | Value::Interval { .. } | Value::Uuid(_) | Value::Json(_) => {
            // These types don't have a Cell representation yet; encode as null.
        }
    }
    cell
}

// ── query conditions ──────────────────────────────────────────────────────

#[napi]
pub enum ConditionKind {
    Pk,
    BitmapEq,
    RangeInt,
    RangeF64,
    FmContains,
    Ann,
    PkInt64,
    BitmapIn,
    IsNull,
    IsNotNull,
    FmContainsAll,
    SparseMatch,
    MinHashSimilar,
    /// Anchored prefix match `LIKE 'prefix%'` on a Bytes column with a bitmap
    /// index. Exact (no residual re-check) — the bitmap's distinct keys are
    /// enumerated and filtered by prefix. The prefix bytes arrive in `text`.
    BytesPrefix,
}

/// One predicate over the shared row-id space. Set the fields appropriate to
/// `kind`; unused fields are ignored. A `query` takes a conjunction (AND) of
/// these — the differentiator no SQL FTS pipeline can match.
#[napi(object)]
pub struct ConditionSpec {
    pub kind: ConditionKind,
    pub column_id: u16,
    pub int64_lo: Option<BigInt>,
    pub int64_hi: Option<BigInt>,
    pub float64_lo: Option<f64>,
    pub float64_hi: Option<f64>,
    pub text: Option<String>,
    pub values: Option<Vec<String>>,
    pub embedding: Option<Vec<f64>>,
    pub k: Option<u32>,
    /// SparseMatch query token ids (paired with `sparse_weights`).
    pub sparse_tokens: Option<Vec<u32>>,
    /// SparseMatch query token weights (paired with `sparse_tokens`).
    pub sparse_weights: Option<Vec<f64>>,
}

fn build_condition(spec: &ConditionSpec) -> napi::Result<Condition> {
    if matches!(
        spec.kind,
        ConditionKind::Ann | ConditionKind::SparseMatch | ConditionKind::MinHashSimilar
    ) {
        let k = spec.k.unwrap_or(10) as usize;
        if k == 0 || k > mongreldb_core::query::MAX_RETRIEVER_K {
            return Err(napi::Error::new(
                napi::Status::InvalidArg,
                format!(
                    "condition k must be between 1 and {}",
                    mongreldb_core::query::MAX_RETRIEVER_K
                ),
            ));
        }
    }
    if spec
        .values
        .as_ref()
        .is_some_and(|values| values.len() > mongreldb_core::query::MAX_SET_MEMBERS)
        || spec
            .sparse_tokens
            .as_ref()
            .is_some_and(|tokens| tokens.len() > mongreldb_core::query::MAX_SPARSE_TERMS)
    {
        return Err(napi::Error::new(
            napi::Status::InvalidArg,
            "condition cardinality exceeds the public query limit",
        ));
    }
    Ok(match spec.kind {
        ConditionKind::Pk => Condition::Pk(text_bytes(spec)?),
        ConditionKind::BitmapEq => Condition::BitmapEq {
            column_id: spec.column_id,
            value: text_bytes(spec)?,
        },
        ConditionKind::RangeInt => Condition::Range {
            column_id: spec.column_id,
            lo: spec
                .int64_lo
                .as_ref()
                .map(bigint_to_i64)
                .transpose()?
                .unwrap_or(i64::MIN),
            hi: spec
                .int64_hi
                .as_ref()
                .map(bigint_to_i64)
                .transpose()?
                .unwrap_or(i64::MAX),
        },
        ConditionKind::RangeF64 => Condition::RangeF64 {
            column_id: spec.column_id,
            lo: spec.float64_lo.unwrap_or(f64::NEG_INFINITY),
            lo_inclusive: true,
            hi: spec.float64_hi.unwrap_or(f64::INFINITY),
            hi_inclusive: true,
        },
        ConditionKind::FmContains => Condition::FmContains {
            column_id: spec.column_id,
            pattern: text_bytes(spec)?,
        },
        ConditionKind::Ann => Condition::Ann {
            column_id: spec.column_id,
            query: spec
                .embedding
                .clone()
                .ok_or_else(|| napi::Error::new(napi::Status::InvalidArg, "Ann needs embedding"))?
                .iter()
                .map(|x| *x as f32)
                .collect(),
            k: spec.k.unwrap_or(10) as usize,
        },
        ConditionKind::PkInt64 => Condition::Pk(
            bigint_to_i64(spec.int64_lo.as_ref().ok_or_else(|| {
                napi::Error::new(napi::Status::InvalidArg, "PkInt64 needs int64_lo")
            })?)?
            .to_be_bytes()
            .to_vec(),
        ),
        ConditionKind::BitmapIn => Condition::BitmapIn {
            column_id: spec.column_id,
            values: text_values(spec)?,
        },
        ConditionKind::IsNull => Condition::IsNull {
            column_id: spec.column_id,
        },
        ConditionKind::IsNotNull => Condition::IsNotNull {
            column_id: spec.column_id,
        },
        ConditionKind::FmContainsAll => Condition::FmContainsAll {
            column_id: spec.column_id,
            patterns: text_values(spec)?,
        },
        ConditionKind::SparseMatch => {
            let tokens = spec.sparse_tokens.clone().ok_or_else(|| {
                napi::Error::new(napi::Status::InvalidArg, "SparseMatch needs sparse_tokens")
            })?;
            let weights = spec.sparse_weights.clone().unwrap_or_default();
            Condition::SparseMatch {
                column_id: spec.column_id,
                query: tokens
                    .into_iter()
                    .zip(weights.into_iter().chain(std::iter::repeat(1.0)))
                    .map(|(t, w)| (t, w as f32))
                    .collect(),
                k: spec.k.unwrap_or(10) as usize,
            }
        }
        ConditionKind::MinHashSimilar => {
            // The query set arrives as `values` (token strings); hash them with
            // the same core function that hashed the indexed documents' tokens.
            let members = spec.values.clone().unwrap_or_default();
            Condition::MinHashSimilar {
                column_id: spec.column_id,
                query: members
                    .iter()
                    .map(|s| mongreldb_core::index::minhash_token_hash(s))
                    .collect(),
                k: spec.k.unwrap_or(10) as usize,
            }
        }
        ConditionKind::BytesPrefix => Condition::BytesPrefix {
            column_id: spec.column_id,
            prefix: text_bytes(spec)?,
        },
    })
}

fn text_bytes(spec: &ConditionSpec) -> napi::Result<Vec<u8>> {
    spec.text
        .as_ref()
        .map(|s| s.as_bytes().to_vec())
        .ok_or_else(|| napi::Error::new(napi::Status::InvalidArg, "expected `text`"))
}

fn text_values(spec: &ConditionSpec) -> napi::Result<Vec<Vec<u8>>> {
    spec.values
        .as_ref()
        .map(|values| values.iter().map(|s| s.as_bytes().to_vec()).collect())
        .ok_or_else(|| napi::Error::new(napi::Status::InvalidArg, "expected `values`"))
}

fn build_conditions(specs: &[ConditionSpec]) -> napi::Result<Vec<Condition>> {
    if specs.len() > mongreldb_core::query::MAX_HARD_CONDITIONS {
        return Err(napi::Error::new(
            napi::Status::InvalidArg,
            format!(
                "query exceeds {} conditions",
                mongreldb_core::query::MAX_HARD_CONDITIONS
            ),
        ));
    }
    specs.iter().map(build_condition).collect()
}

fn finite_f32s(values: &[f64], field: &str) -> napi::Result<Vec<f32>> {
    values
        .iter()
        .map(|value| {
            let value = *value as f32;
            value.is_finite().then_some(value).ok_or_else(|| {
                napi::Error::new(
                    napi::Status::InvalidArg,
                    format!("{field} values must be finite"),
                )
            })
        })
        .collect()
}

fn build_search_request(spec: &SearchSpecJs) -> napi::Result<SearchRequest> {
    let limit = spec.limit as usize;
    if limit == 0 || limit > mongreldb_core::query::MAX_FINAL_LIMIT {
        return Err(napi::Error::new(
            napi::Status::InvalidArg,
            format!(
                "search limit must be between 1 and {}",
                mongreldb_core::query::MAX_FINAL_LIMIT
            ),
        ));
    }
    if spec.retrievers.is_empty() {
        return Err(napi::Error::new(
            napi::Status::InvalidArg,
            "search requires at least one retriever",
        ));
    }
    let must = match &spec.must {
        Some(conds) => build_conditions(conds)?,
        None => Vec::new(),
    };
    let mut retrievers = Vec::with_capacity(spec.retrievers.len());
    for r in &spec.retrievers {
        let k = r.k as usize;
        if k == 0 || k > mongreldb_core::query::MAX_RETRIEVER_K {
            return Err(napi::Error::new(
                napi::Status::InvalidArg,
                format!(
                    "retriever k must be between 1 and {}",
                    mongreldb_core::query::MAX_RETRIEVER_K
                ),
            ));
        }
        if r.name.is_empty() || r.name.len() > mongreldb_core::query::MAX_RETRIEVER_NAME_BYTES {
            return Err(napi::Error::new(
                napi::Status::InvalidArg,
                "retriever name must be non-empty and within the byte limit",
            ));
        }
        if !r.weight.is_finite()
            || r.weight < 0.0
            || r.weight > mongreldb_core::query::MAX_RETRIEVER_WEIGHT
        {
            return Err(napi::Error::new(
                napi::Status::InvalidArg,
                "retriever weight must be finite, non-negative, and within limit",
            ));
        }
        let retriever = match r.kind.as_str() {
            "ann" => {
                let embedding = r.embedding.as_ref().ok_or_else(|| {
                    napi::Error::new(napi::Status::InvalidArg, "ann retriever requires embedding")
                })?;
                let query = finite_f32s(embedding, "embedding")?;
                if query.is_empty() {
                    return Err(napi::Error::new(
                        napi::Status::InvalidArg,
                        "ann retriever requires a non-empty embedding",
                    ));
                }
                Retriever::Ann {
                    column_id: r.column_id,
                    query,
                    k,
                }
            }
            "sparse" => {
                let tokens = r.sparse_tokens.clone().unwrap_or_default();
                let weights = r.sparse_weights.clone().unwrap_or_default();
                if tokens.len() != weights.len() && !weights.is_empty() {
                    return Err(napi::Error::new(
                        napi::Status::InvalidArg,
                        "sparse_tokens and sparse_weights length mismatch",
                    ));
                }
                let query: Vec<(u32, f32)> = if weights.is_empty() {
                    tokens.into_iter().map(|t| (t, 1.0)).collect()
                } else {
                    tokens
                        .into_iter()
                        .zip(weights)
                        .map(|(t, w)| (t, w as f32))
                        .collect()
                };
                Retriever::Sparse {
                    column_id: r.column_id,
                    query,
                    k,
                }
            }
            "minhash" => {
                let members = r
                    .members
                    .clone()
                    .unwrap_or_default()
                    .into_iter()
                    .map(SetMember::String)
                    .collect();
                Retriever::MinHash {
                    column_id: r.column_id,
                    members,
                    k,
                }
            }
            other => {
                return Err(napi::Error::new(
                    napi::Status::InvalidArg,
                    format!("unknown retriever kind {other:?}; expected ann, sparse, or minhash"),
                ))
            }
        };
        retrievers.push(NamedRetriever {
            name: r.name.clone(),
            weight: r.weight,
            retriever,
        });
    }
    let fusion = Fusion::ReciprocalRank {
        constant: spec.fusion_constant.unwrap_or(60).max(1),
    };
    let rerank = match &spec.rerank {
        None => None,
        Some(rr) => {
            let candidate_limit = rr.candidate_limit as usize;
            if candidate_limit < limit || candidate_limit > mongreldb_core::query::MAX_RETRIEVER_K {
                return Err(napi::Error::new(
                    napi::Status::InvalidArg,
                    "rerank candidate_limit is out of range",
                ));
            }
            let metric = match rr.metric.as_str() {
                "cosine" => VectorMetric::Cosine,
                "dot_product" | "dot" => VectorMetric::DotProduct,
                "euclidean" | "l2" => VectorMetric::Euclidean,
                _ => {
                    return Err(napi::Error::new(
                        napi::Status::InvalidArg,
                        "metric must be cosine, dot_product, or euclidean",
                    ))
                }
            };
            Some(Rerank::ExactVector {
                embedding_column: rr.embedding_column,
                query: finite_f32s(&rr.query, "rerank query")?,
                metric,
                candidate_limit,
                weight: rr.weight,
            })
        }
    };
    let projection = spec.projection.clone();
    if let Some(proj) = &projection {
        if proj.len() > mongreldb_core::query::MAX_PROJECTION_COLUMNS {
            return Err(napi::Error::new(
                napi::Status::InvalidArg,
                format!(
                    "projection exceeds {} columns",
                    mongreldb_core::query::MAX_PROJECTION_COLUMNS
                ),
            ));
        }
    }
    Ok(SearchRequest {
        must,
        retrievers,
        fusion,
        rerank,
        limit,
        projection,
    })
}

#[cfg(test)]
mod condition_limit_tests {
    use super::*;

    fn spec(kind: ConditionKind) -> ConditionSpec {
        ConditionSpec {
            kind,
            column_id: 1,
            int64_lo: None,
            int64_hi: None,
            float64_lo: None,
            float64_hi: None,
            text: Some("key".into()),
            values: None,
            embedding: None,
            k: None,
            sparse_tokens: None,
            sparse_weights: None,
        }
    }

    #[test]
    fn napi_condition_limits_are_rejected() {
        let mut ann = spec(ConditionKind::Ann);
        ann.embedding = Some(vec![1.0]);
        ann.k = Some(mongreldb_core::query::MAX_RETRIEVER_K as u32 + 1);
        assert!(build_condition(&ann).is_err());

        let conditions = (0..=mongreldb_core::query::MAX_HARD_CONDITIONS)
            .map(|_| spec(ConditionKind::Pk))
            .collect::<Vec<_>>();
        assert!(build_conditions(&conditions).is_err());
    }
}

fn aggregate_rows_json(
    rows: &[mongreldb_core::memtable::Row],
    column_id: Option<u16>,
    aggregate: &str,
) -> napi::Result<serde_json::Value> {
    if aggregate == "count" {
        return Ok(serde_json::Value::from(rows.len() as u64));
    }
    let column_id = column_id.ok_or_else(|| {
        napi::Error::new(
            napi::Status::InvalidArg,
            format!("columnId is required for {aggregate}"),
        )
    })?;
    let values = rows
        .iter()
        .filter_map(|row| match row.columns.get(&column_id) {
            Some(Value::Int64(value)) => Some(*value as f64),
            Some(Value::Float64(value)) => Some(*value),
            Some(Value::Decimal(value)) => Some(*value as f64),
            _ => None,
        });
    let (sum, count, min, max) = values.fold(
        (0.0, 0u64, f64::INFINITY, f64::NEG_INFINITY),
        |(sum, count, min, max), value| (sum + value, count + 1, min.min(value), max.max(value)),
    );
    let value = match (aggregate, count) {
        (_, 0) => return Ok(serde_json::Value::Null),
        ("sum", _) => sum,
        ("avg", _) => sum / count as f64,
        ("min", _) => min,
        ("max", _) => max,
        _ => {
            return Err(napi::Error::new(
                napi::Status::InvalidArg,
                format!("unknown aggregate '{aggregate}'"),
            ))
        }
    };
    Ok(serde_json::Number::from_f64(value)
        .map(serde_json::Value::Number)
        .unwrap_or(serde_json::Value::Null))
}

fn build_query_from_conditions(conditions: Vec<Condition>) -> Query {
    let mut q = Query::new();
    for c in conditions {
        q = q.and(c);
    }
    q.with_limit(mongreldb_core::query::MAX_FINAL_LIMIT)
}

